const rows = $input.all();
const today = new Date().toISOString().slice(0, 10);

if (rows.length === 0) {
  return [{
    json: {
      message: ':white_check_mark: *Daily Ticket Aging Report* -- ' + today + '\nNo open or pending tickets older than 7 days. All clear!'
    }
  }];
}

const lines = rows.map(item => {
  const d = item.json;
  return ':red_circle: *' + d.account_name + '* -- ' + d.open_ticket_count + ' ticket(s) (open: ' + d.open_count + ', pending: ' + d.pending_count + ') | Oldest: ' + d.oldest_ticket_date;
});

const header = ':rotating_light: *Daily Ticket Aging Report* -- ' + today + '\n_Tickets open or pending, created more than 7 days ago_\n';
const footer = '\n_Total accounts affected: ' + rows.length + '_';

return [{
  json: {
    message: header + '\n' + lines.join('\n') + footer
  }
}];
